package communication;

import jssc.SerialPort;
import jssc.SerialPortException;
import java.nio.ByteBuffer;

public class MsgReceiver {
    final private SerialPort port;

    private enum State {
        WAIT_FOR_MAGIC, READ_KEY, READ_LENGTH, READ_MESSAGE
    }

    public MsgReceiver(String portname) throws SerialPortException {
        port = new SerialPort(portname);
        port.openPort();
        port.setParams(SerialPort.BAUDRATE_9600,
                SerialPort.DATABITS_8,
                SerialPort.STOPBITS_1,
                SerialPort.PARITY_NONE);
    }

    public void run() {
        State currentState = State.WAIT_FOR_MAGIC;
        byte key = 0;
        int length = 0;
        byte[] buffer = new byte[100]; // Assuming max message length as 100
        int bufferIndex = 0;

        while (true) {
            try {
                if (port.getInputBufferBytesCount() > 0) {
                    byte[] readByte = port.readBytes(1);

                    switch (currentState) {
                        case WAIT_FOR_MAGIC:
                            if (readByte[0] == '!') { // Magic number detected
                                currentState = State.READ_KEY;
                            }
                            break;
                        case READ_KEY:
                            key = readByte[0];
                            currentState = State.READ_LENGTH;
                            break;
                        case READ_LENGTH:
                            length = readByte[0] & 0xFF; // Convert to int preserving the unsigned value
                            buffer = new byte[length]; // Allocate buffer with the exact length
                            bufferIndex = 0;
                            currentState = State.READ_MESSAGE;
                            break;
                        case READ_MESSAGE:
                            buffer[bufferIndex++] = readByte[0];
                            if (bufferIndex == length) { // Read complete message
                                processMessage(key, buffer);
                                currentState = State.WAIT_FOR_MAGIC; // Go back to waiting for next message
                            }
                            break;
                    }
                } else {
                    Thread.sleep(10); // No data available; let’s wait a bit
                }
            } catch (Exception ex) {
                System.out.println("Error in run(): " + ex.getMessage());
                break;
            }
        }
    }

    private void processMessage(byte key, byte[] buffer) {
        try {
            switch (key) {
                case 0x30: // UTF-8 string info message
                case 0x31: // UTF-8 string error message
                    String message = new String(buffer, "UTF-8");
                    if (key == 0x30) {
                        System.out.println("Info Message: " + message);
                    } else {
                        System.out.println("Error Message: " + message);
                    }
                    break;
                case 0x32: // 4-byte timestamp
                    if (buffer.length == 4) { // Ensure length is correct for a 4-byte integer
                        int timestamp = ByteBuffer.wrap(buffer).getInt();
                        System.out.println("Timestamp: " + timestamp);
                    }
                    break;
                case 0x33: // 2-byte potentiometer reading
                    if (buffer.length == 2) {
                        int potReading = ByteBuffer.wrap(new byte[]{0x00, 0x00, buffer[0], buffer[1]}).getInt();
                        System.out.println("Potentiometer Reading: " + potReading);
                    }
                    break;
                // Add other cases (e.g., ultrasonic sensor reading) as needed
            }
        } catch (Exception e) {
            System.out.println("Error in processMessage(): " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        try {
            MsgReceiver msgr = new MsgReceiver("/dev/ttyUSB0"); // Replace "/dev/ttyUSB0" with your COM port for Windows, it might be something like "COM3"
            msgr.run();
        } catch (SerialPortException ex) {
            System.out.println("Serial Port Exception: " + ex.getMessage());
        }
    }
}
